"use client"

import * as React from "react"
import {
  IconPhone,
  IconMessageCircle,
  IconMail,
  IconChevronRight,
  IconReceipt,
  IconUmbrella,
  IconCircleCheck,
} from "@tabler/icons-react"
import {
  PageHeader,
  BottomActionBar,
  Button,
  Card,
  CardContent,
  Badge,
  Separator,
  ListCard,
  FilterChips,
  ToggleGroup,
  ToggleGroupItem,
  Textarea,
  Select,
  Input,
  SearchableAccordion,
  Alert,
  AlertTitle,
  AlertDescription,
  formatCurrency,
  cn,
} from "@gunjo/ui"
import type { SearchableAccordionItem, SearchableAccordionCategory } from "@gunjo/ui"

import {
  recentRides,
  goodPointOptions,
  tipOptions,
  lostItemCategories,
  faqEntries,
  faqCategories,
  inquiries,
  inquiryStatusLabels,
  type InquiryStatus,
} from "./data"
import { StarRatingInput } from "./StarRatingInput"
import { InquiryStatusSteps } from "./InquiryStatusSteps"

type Tab = "rate" | "lost" | "faq" | "support"

const STAR_LABELS = [
  "星1つ・とても不満",
  "星2つ・やや不満",
  "星3つ・ふつう",
  "星4つ・満足",
  "星5つ・とても満足",
]

const INQUIRY_BADGE: Record<InquiryStatus, "secondary" | "info" | "warning" | "success"> = {
  received: "secondary",
  checking: "info",
  in_progress: "warning",
  answered: "success",
}

export default function TaxiSupportPage() {
  const [tab, setTab] = React.useState<Tab>("rate")

  // --- 評価フォーム state ---
  const ratedRide = recentRides[0]
  const [stars, setStars] = React.useState(0)
  const [goodPoints, setGoodPoints] = React.useState<string[]>([])
  const [comment, setComment] = React.useState("")
  const [tip, setTip] = React.useState(0)
  const [ratingSubmitted, setRatingSubmitted] = React.useState(false)

  // --- 忘れ物フォーム state ---
  const [lostRideId, setLostRideId] = React.useState(recentRides[0].id)
  const [lostCategory, setLostCategory] = React.useState("")
  const [lostDetail, setLostDetail] = React.useState("")
  const [lostContact, setLostContact] = React.useState("")
  const [lostSubmitted, setLostSubmitted] = React.useState(false)

  // FAQ items for SearchableAccordion
  const faqItems: SearchableAccordionItem[] = React.useMemo(
    () =>
      faqEntries.map((f) => ({
        id: f.id,
        title: f.question,
        body: f.answer,
        category: f.category,
        keywords: f.keywords,
      })),
    []
  )
  const faqCats: SearchableAccordionCategory[] = faqCategories.map((c) => ({
    id: c.id,
    label: c.label,
  }))

  const lostFormValid = Boolean(lostCategory && lostDetail.trim() && lostContact.trim())

  return (
    <div className="mx-auto flex min-h-dvh w-full max-w-md flex-col bg-background">
      <PageHeader
        title="サポート"
        subtitle="群青タクシー"
        onBack={() => undefined}
        align="center"
      />

      {/* セクション切替（横スクロールのチップ） */}
      <div className="border-b border-border bg-background px-4 py-2">
        <FilterChips
          aria-label="サポートの種類"
          value={tab}
          onValueChange={(v) => setTab(v as Tab)}
          items={[
            { value: "rate", label: "乗車の評価" },
            { value: "lost", label: "忘れ物" },
            { value: "faq", label: "よくある質問" },
            { value: "support", label: "問い合わせ" },
          ]}
        />
      </div>

      <main className="flex-1 space-y-6 px-4 py-4 pb-28">
        {tab === "rate" && (
          <RateSection
            ratedRide={ratedRide}
            stars={stars}
            setStars={setStars}
            goodPoints={goodPoints}
            setGoodPoints={setGoodPoints}
            comment={comment}
            setComment={setComment}
            tip={tip}
            setTip={setTip}
            submitted={ratingSubmitted}
          />
        )}

        {tab === "lost" && (
          <LostSection
            lostRideId={lostRideId}
            setLostRideId={setLostRideId}
            lostCategory={lostCategory}
            setLostCategory={setLostCategory}
            lostDetail={lostDetail}
            setLostDetail={setLostDetail}
            lostContact={lostContact}
            setLostContact={setLostContact}
            submitted={lostSubmitted}
          />
        )}

        {tab === "faq" && (
          <section aria-labelledby="faq-heading" className="space-y-3">
            <h2 id="faq-heading" className="text-base font-semibold text-foreground">
              よくある質問
            </h2>
            <SearchableAccordion
              items={faqItems}
              categories={faqCats}
              defaultCategoryValue="all"
              labels={{
                searchPlaceholder: "キーワードで検索（例: 迎車・返金）",
                clearSearchLabel: "検索をクリア",
                allCategoryLabel: "すべて",
                resultCountLabel: (visible, total) => `${total}件中 ${visible}件を表示`,
                clearFiltersLabel: "条件をリセット",
                emptyTitle: "該当する質問が見つかりません",
                emptyDescription: "別のキーワードやカテゴリでお試しください。",
                expandLabel: "表示中をすべて開く",
                collapseLabel: "表示中をすべて閉じる",
                controlsLabel: "よくある質問の操作",
              }}
            />
            <p className="text-xs text-muted-foreground">
              解決しない場合は「問い合わせ」からお気軽にご連絡ください。
            </p>
          </section>
        )}

        {tab === "support" && <SupportSection />}
      </main>

      {/* 下部アクションバー：評価／忘れ物の送信。FAQ・問い合わせタブでは出さない。 */}
      {tab === "rate" && !ratingSubmitted && (
        <BottomActionBar
          actions={
            <Button
              size="lg"
              className="min-h-12 px-6"
              disabled={stars === 0}
              onClick={() => setRatingSubmitted(true)}
            >
              評価を送信する
            </Button>
          }
        >
          <div className="text-sm">
            <span className="font-medium text-foreground">
              {stars > 0 ? `★${stars} を選択中` : "星を選んでください"}
            </span>
            {tip > 0 && (
              <span className="ml-2 text-muted-foreground">
                チップ {formatCurrency(tip)}
              </span>
            )}
          </div>
        </BottomActionBar>
      )}

      {tab === "lost" && !lostSubmitted && (
        <BottomActionBar
          actions={
            <Button
              size="lg"
              className="min-h-12 px-6"
              disabled={!lostFormValid}
              onClick={() => setLostSubmitted(true)}
            >
              問い合わせを送信
            </Button>
          }
        >
          <div className="text-sm text-muted-foreground">
            {lostFormValid ? "内容を確認のうえ送信します" : "必須項目を入力してください"}
          </div>
        </BottomActionBar>
      )}
    </div>
  )
}

/* =========================================================================
 * 乗車の評価
 * ====================================================================== */
function RateSection(props: {
  ratedRide: (typeof recentRides)[number]
  stars: number
  setStars: (n: number) => void
  goodPoints: string[]
  setGoodPoints: (v: string[]) => void
  comment: string
  setComment: (v: string) => void
  tip: number
  setTip: (n: number) => void
  submitted: boolean
}) {
  const {
    ratedRide,
    stars,
    setStars,
    goodPoints,
    setGoodPoints,
    comment,
    setComment,
    tip,
    setTip,
    submitted,
  } = props

  if (submitted) {
    return (
      <Alert variant="success">
        <IconCircleCheck className="size-5" aria-hidden="true" />
        <AlertTitle as="h2">評価を送信しました</AlertTitle>
        <AlertDescription>
          {ratedRide.driver} さんへのフィードバックをありがとうございます。
          {tip > 0 && <> チップ {formatCurrency(tip)} を含めて受け付けました。</>}
        </AlertDescription>
      </Alert>
    )
  }

  return (
    <section aria-labelledby="rate-heading" className="space-y-4">
      <h2 id="rate-heading" className="text-base font-semibold text-foreground">
        直近の乗車を評価
      </h2>

      {/* 対象の乗車サマリ */}
      <Card>
        <CardContent className="space-y-3 p-4">
          <div className="flex items-center justify-between">
            <span className="text-xs text-muted-foreground">{ratedRide.datetime}</span>
            <Badge variant="outline">運賃 {formatCurrency(ratedRide.fare)}</Badge>
          </div>
          <div className="space-y-1 text-sm">
            <div className="flex gap-2">
              <span className="mt-0.5 shrink-0 text-xs text-muted-foreground">乗車</span>
              <span className="text-foreground">{ratedRide.from}</span>
            </div>
            <div className="flex gap-2">
              <span className="mt-0.5 shrink-0 text-xs text-muted-foreground">降車</span>
              <span className="text-foreground">{ratedRide.to}</span>
            </div>
          </div>
          <Separator />
          <div className="text-sm">
            <span className="font-medium text-foreground">{ratedRide.driver}</span>
            <span className="ml-2 text-xs text-muted-foreground">{ratedRide.vehicle}</span>
          </div>
        </CardContent>
      </Card>

      {/* ★評価入力（ハンドロール） */}
      <div className="space-y-2">
        <label className="text-sm font-medium text-foreground" id="stars-label">
          ドライバー評価<span className="ml-1 text-destructive">*</span>
        </label>
        <div className="flex flex-col items-start gap-1">
          <StarRatingInput
            label="ドライバー評価（5段階）"
            value={stars}
            onValueChange={setStars}
            starLabels={STAR_LABELS}
          />
          <span className="text-xs text-muted-foreground" aria-live="polite">
            {stars > 0 ? STAR_LABELS[stars - 1] : "タップして星を選択"}
          </span>
        </div>
      </div>

      {/* 良かった点（複数選択） */}
      <fieldset className="space-y-2">
        <legend className="text-sm font-medium text-foreground">
          良かった点（複数選択可）
        </legend>
        <ToggleGroup
          type="multiple"
          variant="outline"
          value={goodPoints}
          onValueChange={(v: string[]) => setGoodPoints(v)}
          className="flex flex-wrap justify-start gap-2"
        >
          {goodPointOptions.map((opt) => (
            <ToggleGroupItem key={opt.value} value={opt.value} className="rounded-full">
              {opt.label}
            </ToggleGroupItem>
          ))}
        </ToggleGroup>
      </fieldset>

      {/* コメント */}
      <Textarea
        label="コメント（任意）"
        description="ドライバー個人を特定できる内容は控えめにお願いします。"
        placeholder="例：道が混んでいる中、最適なルートを選んでくれました。"
        value={comment}
        onChange={(e) => setComment(e.target.value)}
        rows={4}
      />

      {/* チップ */}
      <fieldset className="space-y-2">
        <legend className="text-sm font-medium text-foreground">チップ（任意）</legend>
        <ToggleGroup
          type="single"
          variant="outline"
          value={String(tip)}
          onValueChange={(v: string) => setTip(v ? Number(v) : 0)}
          className="flex flex-wrap justify-start gap-2"
        >
          {tipOptions.map((amount) => (
            <ToggleGroupItem key={amount} value={String(amount)}>
              {amount === 0 ? "なし" : formatCurrency(amount)}
            </ToggleGroupItem>
          ))}
        </ToggleGroup>
      </fieldset>
    </section>
  )
}

/* =========================================================================
 * 忘れ物の問い合わせ
 * ====================================================================== */
function LostSection(props: {
  lostRideId: string
  setLostRideId: (v: string) => void
  lostCategory: string
  setLostCategory: (v: string) => void
  lostDetail: string
  setLostDetail: (v: string) => void
  lostContact: string
  setLostContact: (v: string) => void
  submitted: boolean
}) {
  const {
    lostRideId,
    setLostRideId,
    lostCategory,
    setLostCategory,
    lostDetail,
    setLostDetail,
    lostContact,
    setLostContact,
    submitted,
  } = props

  if (submitted) {
    return (
      <Alert variant="success">
        <IconCircleCheck className="size-5" aria-hidden="true" />
        <AlertTitle as="h2">忘れ物の問い合わせを受け付けました</AlertTitle>
        <AlertDescription>
          チケット番号 TKT-260628-0099 を発行しました。営業所で確認のうえ、
          ご登録の連絡先へ折り返しご連絡します。「問い合わせ」タブで状況を確認できます。
        </AlertDescription>
      </Alert>
    )
  }

  return (
    <section aria-labelledby="lost-heading" className="space-y-4">
      <h2 id="lost-heading" className="text-base font-semibold text-foreground">
        忘れ物の問い合わせ
      </h2>

      <Alert variant="info">
        <IconUmbrella className="size-5" aria-hidden="true" />
        <AlertTitle>落とし物はお早めに</AlertTitle>
        <AlertDescription>
          乗車から時間が経つほど特定が難しくなります。心当たりの乗車を選んでご連絡ください。
        </AlertDescription>
      </Alert>

      <Select
        label="どの乗車ですか？"
        value={lostRideId}
        onChange={(e) => setLostRideId(e.target.value)}
      >
        {recentRides.map((r) => (
          <option key={r.id} value={r.id}>
            {r.datetime}｜{r.from} → {r.to}
          </option>
        ))}
      </Select>

      <fieldset className="space-y-2">
        <legend className="text-sm font-medium text-foreground">
          品物の種類<span className="ml-1 text-destructive">*</span>
        </legend>
        <FilterChips
          aria-label="品物の種類"
          value={lostCategory}
          onValueChange={setLostCategory}
          items={lostItemCategories.map((c) => ({ value: c.value, label: c.label }))}
        />
      </fieldset>

      <Textarea
        label="特徴・状況"
        description="色・ブランド・中身など、見つけやすい特徴を具体的に。"
        placeholder="例：黒の折りたたみ傘。持ち手にイニシャル「K」のチャーム付き。後部座席に置き忘れたと思います。"
        value={lostDetail}
        onChange={(e) => setLostDetail(e.target.value)}
        rows={4}
      />

      <Input
        label="連絡先（電話番号）"
        description="見つかり次第、こちらの番号へご連絡します。"
        type="tel"
        inputMode="tel"
        placeholder="090-1234-5678"
        value={lostContact}
        onChange={(e) => setLostContact(e.target.value)}
      />
    </section>
  )
}

/* =========================================================================
 * 問い合わせ（履歴 + 連絡手段）
 * ====================================================================== */
function SupportSection() {
  const [openInquiry, setOpenInquiry] = React.useState<string | null>(null)

  return (
    <div className="space-y-6">
      <section aria-labelledby="history-heading" className="space-y-3">
        <h2 id="history-heading" className="text-base font-semibold text-foreground">
          お問い合わせ履歴
        </h2>
        <div className="space-y-2">
          {inquiries.map((inq) => {
            const expanded = openInquiry === inq.id
            return (
              <div key={inq.id} className="space-y-2">
                <ListCard
                  leading={
                    inq.kind === "忘れ物" ? (
                      <IconUmbrella className="size-5 text-muted-foreground" aria-hidden="true" />
                    ) : inq.kind === "料金の異議" ? (
                      <IconReceipt className="size-5 text-muted-foreground" aria-hidden="true" />
                    ) : (
                      <IconMessageCircle className="size-5 text-muted-foreground" aria-hidden="true" />
                    )
                  }
                  title={inq.subject}
                  description={`${inq.ticket}・${inq.kind}`}
                  status={
                    <Badge variant={INQUIRY_BADGE[inq.status]}>
                      {inquiryStatusLabels[inq.status]}
                    </Badge>
                  }
                  meta={`更新 ${inq.updatedAt}`}
                  selected={expanded}
                  onSelect={() => setOpenInquiry(expanded ? null : inq.id)}
                />
                {expanded && (
                  <Card>
                    <CardContent className="space-y-3 p-4">
                      <div className="text-xs text-muted-foreground">
                        受付 {inq.openedAt}・最終更新 {inq.updatedAt}
                      </div>
                      <InquiryStatusSteps status={inq.status} />
                      <Separator />
                      <Button variant="outline" size="sm" className="w-full">
                        スレッドを開く
                        <IconChevronRight className="ml-1 size-4" aria-hidden="true" />
                      </Button>
                    </CardContent>
                  </Card>
                )}
              </div>
            )
          })}
        </div>
      </section>

      <section aria-labelledby="contact-heading" className="space-y-3">
        <h2 id="contact-heading" className="text-base font-semibold text-foreground">
          その他のお問い合わせ
        </h2>
        <div className="space-y-2">
          <ContactRow
            icon={<IconMessageCircle className="size-5" aria-hidden="true" />}
            title="チャットで相談"
            description="24時間・通常2〜3分で返信"
          />
          <ContactRow
            icon={<IconPhone className="size-5" aria-hidden="true" />}
            title="電話で問い合わせ"
            description="0570-000-群青（9:00〜21:00）"
          />
          <ContactRow
            icon={<IconMail className="size-5" aria-hidden="true" />}
            title="メールで問い合わせ"
            description="support@gunjo-taxi.example.jp"
          />
        </div>
      </section>
    </div>
  )
}

function ContactRow(props: {
  icon: React.ReactNode
  title: string
  description: string
}) {
  return (
    <ListCard
      leading={
        <span className={cn("flex size-9 items-center justify-center rounded-full bg-muted text-foreground")}>
          {props.icon}
        </span>
      }
      title={props.title}
      description={props.description}
      onSelect={() => undefined}
    />
  )
}

// Mock domain data for the 乗車後サポート (post-ride support) screen.
// 群青タクシー / GO-style consumer app. No function values — safe to import from a Server Component.

export type Ride = {
