/** 良かった点（複数選択）。 */
export const goodPointOptions: { value: string; label: string }[] = [
  { value: "polite", label: "丁寧な運転" },
  { value: "route", label: "道に詳しい" },
  { value: "clean", label: "車内が清潔" },
  { value: "service", label: "接客が良い" },
  { value: "ontime", label: "時間に正確" },
  { value: "quiet", label: "静かで快適" },
]

/** チップの候補額（円）。 */
