/** 忘れ物の品物カテゴリ。 */
export const lostItemCategories: { value: string; label: string }[] = [
  { value: "umbrella", label: "傘" },
  { value: "phone", label: "スマートフォン" },
  { value: "wallet", label: "財布" },
  { value: "bag", label: "鞄・バッグ" },
  { value: "key", label: "鍵" },
  { value: "other", label: "その他" },
]

/** よくある質問。category は FAQ カテゴリの id。 */
export type FaqEntry = {
  id: string
  category: string
  question: string
  answer: string
  keywords?: string[]
}

export const faqCategories: { id: string; label: string }[] = [
  { id: "fare", label: "料金について" },
  { id: "dispatch", label: "配車について" },
  { id: "payment", label: "支払いについて" },
  { id: "account", label: "アカウント" },
]

export const faqEntries: FaqEntry[] = [
  {
    id: "faq-fare-1",
    category: "fare",
    question: "迎車料金はいくらかかりますか？",
    answer:
      "配車エリア・時間帯により0〜420円の迎車料金がかかります。ご注文確定前の見積もり画面に内訳が表示されます。深夜（22時〜翌5時）は所定の深夜割増が運賃に加算されます。",
    keywords: ["迎車", "深夜", "割増", "料金"],
  },
  {
    id: "faq-fare-2",
    category: "fare",
    question: "請求された料金に納得できません。確認できますか？",
    answer:
      "「お問い合わせ履歴」から該当の乗車を選び「料金の異議」を送信してください。GPSログと実走ルートを照合し、誤課金が確認された場合は差額を返金します。回答まで通常2〜3営業日いただきます。",
    keywords: ["異議", "返金", "誤課金", "高い"],
  },
  {
    id: "faq-fare-3",
    category: "fare",
