import * as React from "react"
import { ApprovalSteps } from "@gunjo/ui"
import type { ApprovalStep } from "@gunjo/ui"

import { inquirySteps, inquiryStatusLabels, type InquiryStatus } from "./data"

/**
 * Consumer-facing inquiry progress: 受付 → 確認中 → 対応中 → 回答済.
 *
 * Reuses @gunjo/ui `ApprovalSteps` (a Timeline-backed status track). It was
 * designed for INTERNAL approval routes (一次承認 etc.), but its state model
 * (approved / current / pending) + `stateLabels` override maps cleanly onto a
 * 4-stage support case. Stages before the current one read `approved`, the
 * current one `current`, later ones `pending`. State is conveyed by icon + text,
 * not colour alone — good for B2C a11y.
 */
export function InquiryStatusSteps({ status }: { status: InquiryStatus }) {
  const currentIndex = inquirySteps.findIndex((s) => s.key === status)

  const steps: ApprovalStep[] = inquirySteps.map((s, i) => ({
    label: inquiryStatusLabels[s.key],
    state: i < currentIndex ? "approved" : i === currentIndex ? "current" : "pending",
  }))

  return (
    <ApprovalSteps
      steps={steps}
      variant="compact"
      // Override the internal-workflow defaults (未着手/対応中/完了) with the
      // consumer support vocabulary so the SR label per step is correct.
      stateLabels={{
        pending: "未着手",
        current: "対応中",
        approved: "完了",
      }}
    />
  )
}

"use client"

import * as React from "react"
import { IconStar, IconStarFilled } from "@tabler/icons-react"
import { cn } from "@gunjo/ui"

export interface StarRatingInputProps {
  /** Current value (0 = 未評価). */
  value: number
  onValueChange: (value: number) => void
  max?: number
  /** Accessible group name. */
  label: string
  /** Per-star text labels announced to SR (e.g. ["とても不満", ...]). */
  starLabels?: string[]
  className?: string
}

/**
 * Hand-rolled INTERACTIVE star rating input.
 *
 * GAP: @gunjo/ui ships `Rating`, but it is `role="img"` display-only (no
 * onChange / no focusable stars). /docs/by-use-case maps "rating INPUT" → Rating,
 * which is wrong for a post-ride 評価 where the user must SET the value. This is
 * the missing piece: a radiogroup of focusable star buttons with hover preview,
 * arrow-key support, and an SR-announced label per star.
 */
export function StarRatingInput({
  value,
  onValueChange,
  max = 5,
  label,
  starLabels,
  className,
}: StarRatingInputProps) {
  const [hover, setHover] = React.useState<number | null>(null)
  const display = hover ?? value

  const onKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    if (e.key === "ArrowRight" || e.key === "ArrowUp") {
      e.preventDefault()
      onValueChange(Math.min(max, value + 1 || 1))
    } else if (e.key === "ArrowLeft" || e.key === "ArrowDown") {
      e.preventDefault()
      onValueChange(Math.max(1, value - 1))
    }
  }

  return (
    <div
      role="radiogroup"
      aria-label={label}
      onKeyDown={onKeyDown}
      className={cn("flex items-center gap-1", className)}
    >
      {Array.from({ length: max }, (_, i) => {
        const star = i + 1
        const active = display >= star
        const isChecked = value === star
        const starLabel = starLabels?.[i] ?? `星${star}つ`
        return (
          <button
            key={star}
            type="button"
            role="radio"
            aria-checked={isChecked}
            aria-label={starLabel}
            tabIndex={isChecked || (value === 0 && star === 1) ? 0 : -1}
            onClick={() => onValueChange(star)}
            onMouseEnter={() => setHover(star)}
            onMouseLeave={() => setHover(null)}
            onFocus={() => setHover(star)}
            onBlur={() => setHover(null)}
            className="inline-flex size-11 items-center justify-center rounded-md outline-none transition-colors hover:bg-accent focus-visible:ring-2 focus-visible:ring-ring"
          >
            {active ? (
              <IconStarFilled className="size-7 text-warning" aria-hidden="true" />
            ) : (
              <IconStar className="size-7 text-muted-foreground" aria-hidden="true" />
            )}
          </button>
        )
      })}
    </div>
  )
}
